# 输入获取
m = int(input())
n = int(input())
sequence = input()


# 算法入口
def getResult(m, n, sequence):
    boardCard = [m * 1.25] * n
    mapping = {"A": 1, "B": 2, "C": 8}

    for i in range(len(sequence)):
        need = 1.25 * mapping[sequence[i]]
        for j in range(n):
            if boardCard[j] >= need:
                boardCard[j] -= need
                break

    for remain in boardCard:
        unUsed = int(remain / 1.25)
        used = m - unUsed
        print('1' * used + '0' * unUsed)


# 算法调用
getResult(m, n, sequence)
